import type { PageLoad } from './$types'
import { createClient } from '$lib/gql/client'
import { gql } from 'graphql-request'
import type { ArtifactTypeDefinition } from '$lib/artifactTypePanel'

const ARTIFACT_DETAIL_QUERY = gql`
	query ArtifactDetail($projectID: ID!, $id: ID!) {
		artifact(projectID: $projectID, id: $id) {
			id
			path
			title
			mediaType
			staleness
			description
			updatedAt
			ddxFrontmatter
			content
			typeDefinitions {
				plugin
				typeId
				name
				description
				prefix
				pattern
				phase
				sourceMetaPath
				template {
					path
					content
					isTruncated
					sizeBytes
				}
				prompt {
					path
					content
					isTruncated
					sizeBytes
				}
				examples {
					path
					description
					content
					isTruncated
					sizeBytes
				}
			}
			generatedBy {
				runId
				promptSummary
				sourceHashMatch
			}
		}
	}
`

const RUN_EXISTS_QUERY = gql`
	query RunExists($id: ID!) {
		run(id: $id) {
			id
		}
	}
`

export interface ArtifactGeneratedBy {
	runId: string
	promptSummary: string
	sourceHashMatch: boolean
}

export interface ArtifactDetail {
	id: string
	path: string
	title: string
	mediaType: string
	staleness: string
	description: string | null
	updatedAt: string | null
	ddxFrontmatter: string | null
	content: string | null
	typeDefinitions: ArtifactTypeDefinition[]
	generatedBy: ArtifactGeneratedBy | null
}

interface ArtifactDetailResult {
	artifact: ArtifactDetail | null
}

export const load: PageLoad = async ({ params, url, fetch }) => {
	const client = createClient(fetch as unknown as typeof globalThis.fetch)
	const data = await client.request<ArtifactDetailResult>(ARTIFACT_DETAIL_QUERY, {
		projectID: params.projectId,
		id: decodeURIComponent(params.artifactId)
	})

	// Build content URL for binary types (images, PDFs, unknown).
	// The UI uses this URL for <img src>, <embed src>, and download links.
	const contentUrl = data.artifact
		? `/api/projects/${encodeURIComponent(params.projectId)}/artifact-content?path=${encodeURIComponent(data.artifact.path)}`
		: null

	// Preserve back-link state so the detail page can return to the filtered list.
	const back = url.searchParams.get('back') ?? null

	// Probe whether the producing run exists, so the UI can disable the link
	// (with tooltip) when the run id is unknown.
	let runExists = false
	const gb = data.artifact?.generatedBy
	if (gb?.runId) {
		try {
			const probe = await client.request<{ run: { id: string } | null }>(RUN_EXISTS_QUERY, {
				id: gb.runId
			})
			runExists = probe.run != null
		} catch {
			runExists = false
		}
	}

	return {
		nodeId: params.nodeId,
		projectId: params.projectId,
		artifactId: params.artifactId,
		artifact: data.artifact,
		contentUrl,
		back,
		runExists
	}
}

// Shared artifact grouping helpers.
// Keep prefix derivation in one place so list and detail views agree.

// prefixOf("docs/helix/01-frame/prd.md") => "docs"
// prefixOf("/library/personas/x.md") => "library"
const PREFIX_RE = /^\/?([^/]+)/;

export function prefixOf(path: string): string {
	const m = path.match(PREFIX_RE);
	return m ? m[1] : '';
}

export interface ArtifactTypeDefinitionFile {
	path: string;
	content: string;
	isTruncated: boolean;
	sizeBytes: number;
}

export interface ArtifactTypeDefinitionExample {
	path: string;
	description?: string | null;
	content: string;
	isTruncated: boolean;
	sizeBytes: number;
}

export interface ArtifactTypeDefinition {
	plugin: string;
	typeId: string;
	name: string;
	description: string;
	prefix: string;
	pattern: string;
	phase: string;
	sourceMetaPath: string;
	template: ArtifactTypeDefinitionFile;
	prompt: ArtifactTypeDefinitionFile;
	examples: ArtifactTypeDefinitionExample[];
}

export type ArtifactTypeTab = 'referencePrompt' | 'template' | 'examples';

export const ARTIFACT_TYPE_TABS: { value: ArtifactTypeTab; label: string }[] = [
	{ value: 'referencePrompt', label: 'Reference Prompt' },
	{ value: 'template', label: 'Template' },
	{ value: 'examples', label: 'Examples' }
];

export function artifactTypeKey(def: ArtifactTypeDefinition): string {
	return `${def.plugin}::${def.typeId}::${def.sourceMetaPath}`;
}

export function artifactTypeLabel(def: ArtifactTypeDefinition): string {
	return def.name || `${def.plugin}/${def.typeId}`;
}

export function hasArtifactTypeCollision(definitions: ArtifactTypeDefinition[]): boolean {
	return definitions.length > 1;
}

export function selectedArtifactTypeDefinition(
	definitions: ArtifactTypeDefinition[],
	typeDefParam: string | null
): ArtifactTypeDefinition | null {
	if (definitions.length === 0) return null;
	if (!typeDefParam) return definitions[0];
	return definitions.find((def) => artifactTypeKey(def) === typeDefParam) ?? definitions[0];
}

export function updateTypeDefUrl(url: URL, typeDefParam: string | null): string {
	const next = new URL(url);
	if (typeDefParam) next.searchParams.set('typeDef', typeDefParam);
	else next.searchParams.delete('typeDef');
	return next.pathname + next.search;
}

